f^{-1}(f^{-1}(g(f(19))))&=f^{-1}(5)\\
\implies f^{-1}(f^{-1}(g(f(19))))&=5-2\\
\implies f^{-1}(f^{-1}(g(f(19))))&=3 
\end{align*}

