g^{-1}(f^{-1}(f^{-1}(g(f(19)))))&=g^{-1}(3)\\
\implies g^{-1}(f^{-1}(f^{-1}(g(f(19)))))&=3 \cdot 3\\
\implies g^{-1}(f^{-1}(f^{-1}(g(f(19)))))&=9 
\end{align*}

\begin{align*}
f(g^{-1}(f^{-1}(f^{-1}(g(f(19))))))&=f(9)\\
\implies f(g^{-1}(f^{-1}(f^{-1}(g(f(19))))))&=9+2\\
\implies f(g^{-1}(f^{-1}(f^{-1}(g(f(19))))))&=11
\end{align*} 
The answer is $$
\boxed{11}
